            th, td { padding: 10px; text-align: left; border-bottom: 1px solid #3e3e3e; }
            th { background: #2d2d2d; color: #4ec9b0; }
        </style>
    </head>
    <body>
        <h1>🔔 User Changes Debug Dashboard</h1>
        <p class="total">Auto-refreshes every 3 seconds | <a href="/api/debug/changes-dashboard" style="color:#4ec9b0;">Refresh Now</a></p>

        <h2 style="color:#569cd6;">Recent Changes (All Sessions)</h2>
        <table>
            <tr>
                <th>Time</th>
                <th>Session</th>
                <th>Field</th>
                <th>Old Value</th>
                <th>New Value</th>
            </tr>
    '''

    for change in _all_changes_list[-20:]:
        all_changes_html += f'''
            <tr>
                <td class="timestamp">{change.get('timestamp', '')[:19]}</td>
                <td class="session">{change.get('session_id', 'unknown')}</td>
                <td class="field">{change.get('field', 'unknown')}</td>
                <td class="old">{change.get('old_value', '-')}</td>
                <td class="new">{change.get('new_value', '-')}</td>
            </tr>
        '''

    all_changes_html += '''
        </table>
        <p style="color:#808080; margin-top:20px;">Total changes tracked: {{ total }}</p>
    </body>
    </html>
    '''.replace('{{ total }}', str(len(_all_changes_list)))

    return render_template_string(all_changes_html)


from services.cache_service import _changes_history
_all_changes_list = []

def _update_all_changes_list():
    global _all_changes_list
    for session_id, changes in _changes_history.items():
        for change in changes:
            change['session_id'] = session_id
            if change not in _all_changes_list:
                _all_changes_list.append(change)
    _all_changes_list = _all_changes_list[-100:]

@app.before_request
def update_debug_data():
    if '/debug/changes-dashboard' in request.path:
        _update_all_changes_list()
